import { defineConfig } from "@trigger.dev/sdk";

export default defineConfig({
  project: "stream-project",
  dirs: ["./trigger"],
  runtime: "node",
  retries: {
    enabledInDev: false,
  },
});

import { client, streams, wait } from "@trigger.dev/sdk";

const trial_id = "cancellable_ai_stream__XZFxibn";

// Define the output stream for AI-generated text
export const aiStream = streams.define<string>({
  id: `aiStream-${trial_id}`,
});

// Define the input stream for cancellation signals
export const cancelStream = streams.input<{ reason?: string }>({
  id: `cancelStream-${trial_id}`,
});

// Create the AI streaming task
export const aiTask = client.defineJob({
  id: `aiTask-${trial_id}`,
  name: "AI Streaming Task with Cancellation",
  version: "1.0.0",
  run: async ({ payload, ctx }) => {
    let cancelled = false;
    let cancelReason: string | undefined;

    // Register a listener on the cancel stream
    cancelStream.on(async (message) => {
      cancelReason = message.reason || "No reason provided";
      console.log(`Cancellation received: ${cancelReason}`);
      cancelled = true;
    });

    // Simulate AI generation with a loop
    const chunks = [
      "Once upon a time, ",
      "in a digital realm, ",
      "there lived an AI assistant ",
      "that could generate stories ",
      "chunk by chunk, ",
      "streaming text in real-time, ",
      "while listening for cancellation, ",
      "ready to stop at any moment, ",
      "making the experience responsive, ",
      "and efficient for the user."
    ];

    for (let i = 0; i < chunks.length; i++) {
      // Check if cancelled before each chunk
      if (cancelled) {
        console.log("Generation cancelled, stopping loop");
        break;
      }

      // Append the chunk to the output stream
      await aiStream.append(chunks[i]);

      // Wait 1 second between chunks (simulating generation time)
      await wait.for({ seconds: 1 });
    }

    // Return final status
    return {
      status: cancelled ? "cancelled" : "completed",
      cancelReason,
      chunksGenerated: cancelled ? chunks.findIndex((_, idx) => idx === i - 1) + 1 : chunks.length,
    };
  },
});

